  "Script": "MailManagement = {\r\n    init: async function (app, container) {\r\n        app = app || session.app;\r\n        container = container || $(\".component[name=MailManagement]\");\r\n        api.addToMetaCache([\r\n            {\r\n                \"Name\": \"Core\",\r\n                \"Types\": [\r\n                    [meta[Mail/QueuedEmail]],\r\n                    [meta[Mail/SentEmail]],\r\n                    [meta[Mail/MailServer]]\r\n                ]\r\n            }\r\n        ]);\r\n\r\n        MailManagement.setupMailSentGrid(app, container);\r\n        MailManagement.setupMailServerGrid(app, container);\r\n        MailManagement.setupMailQueueGrid(app, container);\r\n    },\r\n\r\n    save: async function (e, grid) {\r\n        e.preventDefault();\r\n        var item = grid.dataItem($(e.currentTarget).closest(\"tr\"));\r\n        await item.save().then(notification.success(\"[resource_displayname[saved]]\"));\r\n        grid.refresh();\r\n    },\r\n\r\n    setupMailSentGrid: async function (app, container) {\r\n        var mailSent = await model.getDatasource({ endpoint: \"Mail/SentEmail\", odataAppend: \"?$filter=AppId eq \" + app.Id, sort: { field: \"SentOn\", dir: \"desc\" } });\r\n\r\n        var mailSentGrid = new GridWidget($(\"[name=history]\", container), mailSent);\r\n        mailSentGrid.filterable = true;\r\n\r\n        mailSentGrid.detailTemplate = \"<iframe class='mail-content-frame'></iframe>\"\r\n        mailSentGrid.detailExpand = function (e) {\r\n            var item = mailSentGrid.dataItem($(e.masterRow));\r\n            var element = $(\"iframe\", $(e.detailRow))[0];\r\n            var document = element.contentDocument || element.contentWindow.document;\r\n            document.write(item.Content);\r\n            document.close();\r\n        };\r\n        mailSentGrid.columns = [\r\n            { field: \"Subject\", title: \"[resource_displayname[subject]]\" },\r\n            { field: \"From\", title: \"[resource_displayname[from]]\" },\r\n            { field: \"SentByUserId\", title: \"[resource_displayname[sentbyuserid]]\" },\r\n            { field: \"To\", title: \"[resource_displayname[to]]\" },\r\n            { field: \"CC\", title: \"[resource_displayname[cc]]\" },\r\n            { field: \"SentOn\", title: \"[resource_displayname[senton]]\", type: \"date\", format: \"{0: \" + type.dateFormat + \" HH:mm}\" }\r\n        ];\r\n        mailSentGrid.init();\r\n    },\r\n\r\n    setupMailServerGrid: async function (app, container) {\r\n        var mailServer = await model.getDatasource({ endpoint: \"Mail/MailServer\", odataAppend: \"?$filter=AppId eq \" + app.Id });\r\n\r\n        var mailServerGrid = new GridWidget($(\"[name=mailServer]\", container), mailServer);\r\n        mailServerGrid.filterable = true;\r\n        mailServerGrid.editable = true;\r\n        mailServerGrid.groupable = false;\r\n        mailServerGrid.toolbar = \"<div class='btn-group btn-group-sm'> <button class='btn btn-primary' name='create'> <span class='k-icon k-i-plus'></span>[resource_displayname[new]] </button> </div>\";\r\n        mailServerGrid.columns = [\r\n            { field: \"Name\", title: \"[resource_displayname[name]]\" },\r\n            { field: \"FromEmail\", title: \"[resource_displayname[fromEmail]]\" },\r\n            { field: \"User\", title: \"[resource_displayname[user]]\" },\r\n            { field: \"Password\", title: \"[resource_displayname[password]]\", template: \"#='*'.repeat(Password.length)#\" },\r\n            { field: \"Host\", title: \"[resource_displayname[host]]\" },\r\n            { field: \"Port\", title: \"[resource_displayname[port]]\" },\r\n            { field: \"EnableSSL\", title: \"[resource_displayname[enablessl]]\" },\r\n        ];\r\n        mailServerGrid.commands.push({ name: \"save\", icon: \"k-i-save\", text: \"[resource_displayname[save]]\" });\r\n        mailServerGrid.commands.push({ name: \"remove\", icon: \"k-i-trashIcon\", text: \"[resource_displayname[delete]]\" });\r\n        mailServerGrid.dataBound = function (e) {\r\n            $(\"[name=save]\", mailServerGrid.gridElement).off(\"click\").on(\"click\", (e) => MailManagement.save(e, mailServerGrid));\r\n            $(\"[name=remove]\", mailServerGrid.gridElement).off(\"click\").on(\"click\", (e) => MailManagement.remove(e, mailServerGrid));\r\n            $(\"button[name=create]\", mailServerGrid.gridElement).on(\"click\", (e) => MailManagement.newMailServer(e, mailServerGrid, app));\r\n        };\r\n        mailServerGrid.init();\r\n    },\r\n\r\n    setupMailQueueGrid: async function (app, container) {\r\n        var mailQueue = await model.getDatasource({ endpoint: \"Mail/QueuedEmail\", odataAppend: \"?$filter=AppId eq \" + app.Id + \"&$expand=FailedSends\" });\r\n\r\n        var mailQueueGrid = new GridWidget($(\"[name=queue]\", container), mailQueue);\r\n        mailQueueGrid.filterable = true;\r\n        mailQueueGrid.detailTemplate = $(\"[name=mailQueueExpand]\").first().html();\r\n        mailQueueGrid.detailExpand = function (e) {\r\n            var item = mailQueueGrid.dataItem($(e.masterRow));\r\n            $(\"[name=mailTabs]\", $(e.detailRow)).kendoTabStrip({ animation: { open: { effects: \"fadeIn\" } } });\r\n\r\n            var element = $(\"iframe\", $(e.detailRow))[0];\r\n            var document = element.contentDocument || element.contentWindow.document;\r\n            document.write(item.Content);\r\n            document.close();\r\n\r\n            var grid = new GridWidget($(\"[name=failuresTab]\", $(e.detailRow)), { data: item.FailedSends, pageSize: 50, sort: { field: \"AttemptedOn\", dir: \"desc\" } });\r\n            grid.filterable = false;\r\n            grid.groupable = false;\r\n            grid.columns = [\r\n                { field: \"AttemptedOn\", type: \"date\", format: \"{0: \" + type.dateFormat + \"  HH:mm}\", title: \"[resource_displayname[attemptedon]]\" },\r\n                { field: \"FailureReason\", title: \"[resource_displayname[failurereason]]\" },\r\n            ];\r\n            grid.init();\r\n        };\r\n\r\n        mailQueueGrid.dataBound = function () {\r\n            $(\"[name=destroy]\", mailQueueGrid.gridElement).on(\"click\", async (e) => {\r\n                var item = mailQueueGrid.dataItem($(e.currentTarget).closest(\"tr\"));\r\n                await api.destroy(\"Mail/QueuedEmail(\" + item.Id + \")\").then(() => {\r\n                    notification.success(\"[resource_displayname[deleted]]\");\r\n                    mailQueueGrid.refresh();\r\n                }).catch((err) => error(err));\r\n            });\r\n        };\r\n\r\n        mailQueueGrid.commands.push({ name: \"destroy\", icon: \"k-i-delete\", text: \"[resource_displayname[delete]]\" });\r\n        mailQueueGrid.columns = [\r\n            { field: \"Subject\", title: \"[resource_displayname[subject]]\" },\r\n            { field: \"SentByUserId\", title: \"[resource_displayname[sentbyuserid]]\" },\r\n            { field: \"To\", title: \"[resource_displayname[to]]\" },\r\n            { field: \"CC\", title: \"[resource_displayname[cc]]\" },\r\n        ];\r\n        mailQueueGrid.init();\r\n    },\r\n\r\n    remove: async function (e, grid) {\r\n        e.preventDefault();\r\n        var item = grid.kendoObject.dataItem($(e.currentTarget).closest(\"tr\"));\r\n        await api.destroy(\"Mail/MailServer(\" + item.Id + \")\").then(async () => {\r\n            notification.success(\"[resource_displayname[deleted]]\");\r\n            grid.refresh();\r\n        }).catch((err) => error(err));\r\n    },\r\n\r\n    newMailServer: async function (e, grid, app) {\r\n        e.preventDefault();\r\n        var newMailServer = {\r\n            Id: 0,\r\n            AppId: app.Id,\r\n            Name: \"\",\r\n            User: \"\",\r\n            Password: \"\",\r\n            Host: \"\",\r\n            Port: \"\",\r\n            EnableSSL: true\r\n        };\r\n        var args = {\r\n            fields: [\r\n                { field: \"Name\", title: \"[resource_displayname[name]]\", description: \"[resource_description[name]]\" },\r\n                { field: \"User\", title: \"[resource_displayname[user]]\", description: \"[resource_description[user]]\" },\r\n                { field: \"Password\", title: \"[resource_displayname[password]]\", description: \"[resource_description[password]]\" },\r\n                { field: \"Host\", title: \"[resource_displayname[host]]\", description: \"[resource_description[host]]\" },\r\n                { field: \"Port\", title: \"[resource_displayname[port]]\", description: \"[resource_description[port]]\" },\r\n                { field: \"EnableSSL\", title: \"[resource_displayname[enablessl]]\", description: \"[resource_description[enablessl]]\" },\r\n            ],\r\n            title: \"[resource_displayname[createnewmailserver]]\",\r\n            data: newMailServer,\r\n            confirm: \"[resource_displayname[confirm]]\",\r\n            close: \"[resource_displayname[close]]\"\r\n        };\r\n        var addMailServerDialog = new EditorDialog(args);\r\n        addMailServerDialog.events.confirm = async function () {\r\n            await api.add(\"Mail/MailServer\", addMailServerDialog.data.toJSON()).then(() => {\r\n                addMailServerDialog.events.close();\r\n                notification.success(\"[resource_displayname[created]]\");\r\n                grid.refresh();\r\n            }).catch((err) => error(err));\r\n        };\r\n        addMailServerDialog.init();\r\n    },\r\n}",
  "Content": "<div class=\"tab-control\">\r\n    <nav>\r\n        <div class=\"nav nav-tabs\" id=\"mail-management-nav-tab\" role=\"tablist\">\r\n            <button class=\"nav-link bg active\" id=\"mail-management-queue-tab\" data-bs-toggle=\"tab\" data-bs-target=\"#mail-management-queue\" aria-selected=\"true\" role=\"tab\">\r\n                <span class=\"k-icon k-i-group-section\"></span>\r\n                [resource_displayname[queue]]\r\n            </button>\r\n            <button class=\"nav-link bg\" id=\"mail-management-history-tab\" data-bs-toggle=\"tab\" data-bs-target=\"#mail-management-history\" aria-selected=\"false\" role=\"tab\">\r\n                <span class=\"k-icon k-i-clock\"></span>\r\n                [resource_displayname[history]]\r\n            </button>\r\n            <button class=\"nav-link bg\" id=\"mail-management-mail-server-tab\" data-bs-toggle=\"tab\" data-bs-target=\"#mail-management-mail-server\" aria-selected=\"false\" role=\"tab\">\r\n                <span class=\"k-icon k-i-arrows-swap\"></span>\r\n                [resource_displayname[mailserver]]\r\n            </button>\r\n        </div>\r\n    </nav>\r\n\r\n    <div class=\"tab-content\" id=\"mail-management-nav-tabContent\">\r\n        <div class=\"tab-pane fade active show\" id=\"mail-management-queue\" role=\"tabpanel\" aria-labelledby=\"mail-management-queue-tab\" name=\"queue\"></div>\r\n        <div class=\"tab-pane fade\" id=\"mail-management-history\" role=\"tabpanel\" aria-labelledby=\"mail-management-history-tab\" name=\"history\"></div>\r\n        <div class=\"tab-pane fade\" id=\"mail-management-mail-server\" role=\"tabpanel\" aria-labelledby=\"mail-management-mail-server-tab\" name=\"mailServer\"></div>\r\n    </div>\r\n</div>\r\n\r\n<script type=\"text/template\" name=\"mailQueueExpand\">\r\n<div name=\"mailTabs\">\r\n\t<ul>\r\n\t\t<li class=\"k-active\">[resource_displayname[preview]]</li>\r\n\t\t<li>[resource_displayname[failures]]</li>\r\n\t</ul>\r\n\t<div class=\"tab\" name=\"preview\">\r\n\t\t<iframe></iframe>\r\n\t</div>\r\n\t<div class=\"tab\" name=\"failuresTab\"></div>\r\n</div>\r\n</script>",
